3	import mage.Mana;
4	import mage.abilities.Ability;
5	import mage.abilities.AbilityImpl;
6	import mage.abilities.costs.*;
7	import mage.abilities.costs.common.PayLifeCost;
8	import mage.abilities.costs.common.WaterbendCost;
9	import mage.abilities.mana.ManaOptions;
10	import mage.constants.ColoredManaSymbol;
11	import mage.constants.ManaType;
12	import mage.constants.Outcome;
13	import mage.filter.Filter;
14	import mage.filter.StaticFilters;
15	import mage.game.Game;
16	import mage.game.events.GameEvent;
17	import mage.game.permanent.Permanent;
18	import mage.players.ManaPool;
19	import mage.players.Player;
20	import mage.target.TargetPermanent;
21	import mage.target.Targets;
22	import mage.target.common.TargetControlledPermanent;
