26	import java.util.*;
27	import java.util.concurrent.ConcurrentHashMap;
28	import java.util.stream.Collectors;
29	
30	/**
31	 * @param <T>
32	 * @author BetaSteward_at_googlemail.com
33	 */
34	public class ManaCostsImpl<T extends ManaCost> extends ArrayList<T> implements ManaCosts<T> {
35	
36	    protected final UUID id;
37	    protected String text = null;
38	    protected boolean phyrexian = false;
39	    private int phyrexianPaid = 0;
40	
41	    private static final Map<String, ManaCosts> costsCache = new ConcurrentHashMap<>(); // must be thread safe, can't use nulls
42	
43	    public ManaCostsImpl() {
44	        this.id = UUID.randomUUID();
45	    }
46	
47	    public ManaCostsImpl(String mana) {
48	        this.id = UUID.randomUUID();
49	        load(mana);
50	    }
51	
52	    protected ManaCostsImpl(final ManaCostsImpl<T> costs) {
53	        this.id = costs.id;
54	        this.text = costs.text;
55	        this.ensureCapacity(costs.size());
56	        for (T cost : costs) {
57	            this.add(cost.copy());
58	        }
59	        this.phyrexian = costs.phyrexian;
60	        this.phyrexianPaid = costs.phyrexianPaid;
61	    }
62	
63	    @Override
64	    public final boolean add(ManaCost cost) {
65	        if (cost instanceof ManaCosts) {
66	            for (ManaCost manaCost : (ManaCosts<T>) cost) {
67	                super.add((T) manaCost);
68	            }
69	            return true;
70	        } else {
71	            return super.add((T) cost);
72	        }
73	    }
74	
75	    @Override
76	    public int manaValue() {
77	        int total = 0;
78	        for (ManaCost cost : this) {
79	            total += cost.manaValue();
80	        }
81	        return total;
82	    }
83	
84	    @Override
85	    public Mana getMana() {
86	        Mana mana = new Mana();
87	        for (ManaCost cost : this) {
88	            mana.add(cost.getMana());
89	        }
90	        return mana;
91	    }
92	
93	    @Override
94	    public List<Mana> getManaOptions() {
95	        List<Mana> manaVariants = new ArrayList<>();
96	        for (ManaCost cost : this) {
97	            manaVariants.addAll(cost.getManaOptions());
98	        }
99	        return manaVariants;
100	    }
101	
102	    @Override
103	    public Mana getPayment() {
104	        Mana manaTotal = new Mana();
105	        for (ManaCost cost : this) {
106	            manaTotal.add(cost.getPayment());
107	        }
108	        return manaTotal;
109	    }
110	
111	    @Override
112	    public Mana getUsedManaToPay() {
113	        Mana manaTotal = new Mana();
114	        for (ManaCost cost : this) {
115	            manaTotal.add(cost.getUsedManaToPay());
116	        }
117	        return manaTotal;
118	    }
119	
120	    @Override
121	    public boolean pay(Ability ability, Game game, Ability source, UUID controllerId, boolean noMana) {
122	        return pay(ability, game, source, controllerId, noMana, this);
123	    }
124	
125	    @Override
126	    public boolean pay(Ability ability, Game game, Ability source, UUID playerId, boolean noMana, Cost costToPay) {
127	        if (this.isEmpty() || noMana) {
128	            setPaid();
129	            return true;
130	        }
131	
132	        Player player = game.getPlayer(playerId);
133	        if (player == null) {
134	            return false;
135	        }
136	
137	        AbilityImpl.handlePhyrexianLikeEffects(game, source, ability, this);
138	
139	        if (!player.getManaPool().isForcedToPay()) {
140	            assignPayment(game, ability, player.getManaPool(), costToPay != null ? costToPay : this);
141	        }
142	        game.getState().getSpecialActions().removeManaActions();
143	        while (player.canRespond() && !isPaid()) {
144	            ManaCost unpaid = this.getUnpaid();
145	            String promptText = ManaUtil.addSpecialManaPayAbilities(ability, game, unpaid);
146	            if (player.playMana(ability, unpaid, promptText, game)) {
147	                assignPayment(game, ability, player.getManaPool(), costToPay != null ? costToPay : this);
148	            } else {
149	                return false;
150	            }
151	            game.getState().getSpecialActions().removeManaActions();
152	        }
153	        return isPaid();
154	    }
155	
156	    /**
157	     * bookmarks the current state and restores it if player doesn't pay the
158	     * mana cost
159	     *
160	     * @param ability
161	     * @param game
162	     * @param source
163	     * @param payingPlayerId
164	     * @return true if the cost was paid
165	     */
166	    @Override
167	    public boolean payOrRollback(Ability ability, Game game, Ability source, UUID payingPlayerId) {
168	        Player payingPlayer = game.getPlayer(payingPlayerId);
169	        if (payingPlayer != null) {
170	            int bookmark = game.bookmarkState();
171	            handlePhyrexianManaCosts(ability, payingPlayer, source, game);
172	            handleWaterbendingCosts(ability, payingPlayer, source, game);
173	            if (pay(ability, game, source, payingPlayerId, false, null)) {
174	                game.removeBookmark(bookmark);
175	                return true;
176	            }
177	            payingPlayer.restoreState(bookmark, ability.getRule(), game);
178	        }
179	        return false;
180	    }
181	
182	    private void handlePhyrexianManaCosts(Ability abilityToPay, Player payingPlayer, Ability source, Game game) {
183	        if (this.isEmpty()) {
184	            return; // nothing to be done without any mana costs. prevents NRE from occurring here
185	        }
186	        Iterator<T> manaCostIterator = this.iterator();
187	        Costs<PayLifeCost> tempCosts = new CostsImpl<>();
188	
189	        while (manaCostIterator.hasNext()) {
190	            ManaCost manaCost = manaCostIterator.next();
191	            if (!manaCost.isPhyrexian()) {
192	                continue;
193	            }
194	            PayLifeCost payLifeCost = new PayLifeCost(2);
195	            if (payLifeCost.canPay(abilityToPay, source, payingPlayer.getId(), game)
196	                    && payingPlayer.chooseUse(Outcome.LoseLife, "Pay 2 life instead of " + manaCost.getText().replace("/P", "") + '?', source, game)) {
197	                manaCostIterator.remove();
198	                tempCosts.add(payLifeCost);
199	                this.incrPhyrexianPaid();
200	            }
201	        }
202	
203	        tempCosts.pay(source, game, source, payingPlayer.getId(), false, null);
204	    }
205	
206	    private void handleWaterbendingCosts(Ability abilityToPay, Player payingPlayer, Ability source, Game game) {
207	        int total = CardUtil
208	                .castStream(this, WaterbendCost.class)
209	                .mapToInt(WaterbendCost::manaValue)
210	                .sum();
211	        if (total < 1) {
212	            return;
213	        }
214	        TargetPermanent target = new TargetControlledPermanent(
215	                0, total, StaticFilters.FILTER_CONTROLLED_UNTAPPED_ARTIFACT_OR_CREATURE, true
216	        );
217	        target.withChooseHint("to tap for waterbending");
218	        payingPlayer.choose(Outcome.Tap, target, source, game);
219	        Set<Permanent> permanents = target
220	                .getTargets()
221	                .stream()
222	                .map(game::getPermanent)
223	                .filter(Objects::nonNull)
224	                .collect(Collectors.toSet());
225	        for (Permanent permanent : permanents) {
226	            permanent.tap(source, game);
227	        }
228	        this.removeIf(WaterbendCost.class::isInstance);
229	        this.add(new GenericManaCost(total - permanents.size()));
230	        game.fireEvent(GameEvent.getEvent(GameEvent.EventType.WATERBENDED, source.getSourceId(), source, payingPlayer.getId(), total));
231	    }
232	
233	    @Override
234	    public ManaCosts<T> getUnpaid() {
235	        ManaCosts<T> unpaid = new ManaCostsImpl<>();
236	        for (T cost : this) {
237	            if (!(cost instanceof VariableManaCost) && !cost.isPaid()) {
238	                unpaid.add((T) cost.getUnpaid());
239	            }
240	        }
241	        return unpaid;
242	    }
243	
244	    @Override
245	    public ManaCosts<T> getUnpaidVariableCosts() {
246	        ManaCosts<T> unpaid = new ManaCostsImpl<>();
247	        for (ManaCost cost : this) {
248	            if (cost instanceof VariableManaCost && !cost.isPaid()) {
249	                unpaid.add((T) cost.getUnpaid());
250	            }
251	        }
252	        return unpaid;
253	    }
254	
255	    @Override
256	    public List<VariableCost> getVariableCosts() {
257	        List<VariableCost> variableCosts = new ArrayList<>();
258	        for (ManaCost cost : this) {
259	            if (cost instanceof VariableCost) {
260	                variableCosts.add((VariableCost) cost);
261	            }
262	        }
263	        return variableCosts;
264	    }
265	
266	    @Override
267	    public boolean containsX() {
268	        return !getVariableCosts().isEmpty();
269	    }
270	
271	    @Override
272	    public void setX(int xValue, int xPay) {
273	        List<VariableCost> variableCosts = getVariableCosts();
274	        if (!variableCosts.isEmpty()) {
275	            variableCosts.get(0).setAmount(xValue, xPay, false);
276	        }
277	    }
278	
279	    @Override
280	    public void setPayment(Mana mana) {
281	    }
282	
283	    private boolean canPayColoredManaFromPool(ManaType needColor, ManaCost cost, ManaType canUseManaType, ManaPool pool) {
284	        if (canUseManaType == null || canUseManaType.equals(needColor)) {
285	            return cost.containsColor(CardUtil.manaTypeToColoredManaSymbol(needColor))
286	                    && (pool.getColoredAmount(needColor) > 0 || pool.conditionalManaHasManaType(needColor));
287	        }
288	        return false;
289	    }
290	
291	    @Override
292	    public void assignPayment(Game game, Ability ability, ManaPool pool, Cost costToPay) {
293	        // try to assign mana from pool to payment in priority order (color first)
294	
295	        // auto-payment allows to use any mana type, if not then only unlocked can be used (mana type that were clicked in mana pool)
296	        ManaType canUseManaType;
297	        if (pool.isAutoPayment()) {
298	            canUseManaType = null; // can use any type
299	        } else {
300	            canUseManaType = pool.getUnlockedManaType();
301	            if (canUseManaType == null) {
302	                // auto payment is inactive and no mana type was clicked manually - do nothing
303	                return;
304	            }
305	        }
306	
307	        ManaCosts referenceCosts = null;
308	        if (pool.isForcedToPay()) {
309	            referenceCosts = this.copy();
310	        }
311	
312	        // colorless costs (not generic)
313	        for (ManaCost cost : this) {
314	            if (!cost.isPaid() && cost instanceof ColorlessManaCost) {
315	                cost.assignPayment(game, ability, pool, costToPay);
316	                if (pool.isEmpty()) {
317	                    return;
318	                }
319	            }
320	        }
321	
322	        // colored
323	        for (ManaCost cost : this) {
324	            if (!cost.isPaid() && cost instanceof ColoredManaCost) {
325	                cost.assignPayment(game, ability, pool, costToPay);
326	                if (pool.isEmpty()) {
327	                    return;
328	                }
329	            }
330	        }
331	
332	        // hybrid
333	        for (ManaCost cost : this) {
334	            if (!cost.isPaid() && cost instanceof HybridManaCost) {
335	                cost.assignPayment(game, ability, pool, costToPay);
336	                if (pool.isEmpty()) {
337	                    return;
338	                }
339	            }
340	        }
341	
342	        // Colorless hybrid
343	        for (ManaCost cost : this) {
344	            if (!cost.isPaid() && cost instanceof ColorlessHybridManaCost) {
345	                cost.assignPayment(game, ability, pool, costToPay);
346	                if (pool.isEmpty()) {
347	                    return;
348	                }
349	            }
350	        }
351	
352	        // monohybrid
353	        // try to pay colored part
354	        for (ManaCost cost : this) {
355	            if (!cost.isPaid() && cost instanceof MonoHybridManaCost) {
356	                if (canPayColoredManaFromPool(ManaType.WHITE, cost, canUseManaType, pool)
357	                        || canPayColoredManaFromPool(ManaType.BLACK, cost, canUseManaType, pool)
358	                        || canPayColoredManaFromPool(ManaType.RED, cost, canUseManaType, pool)
359	                        || canPayColoredManaFromPool(ManaType.GREEN, cost, canUseManaType, pool)
360	                        || canPayColoredManaFromPool(ManaType.BLUE, cost, canUseManaType, pool)) {
361	                    cost.assignPayment(game, ability, pool, costToPay);
362	                    if (pool.isEmpty() && pool.getConditionalMana().isEmpty()) {
363	                        return;
364	                    }
365	                }
366	            }
367	        }
368	        // try to pay generic part
369	        for (ManaCost cost : this) {
370	            if (!cost.isPaid() && cost instanceof MonoHybridManaCost) {
371	                cost.assignPayment(game, ability, pool, costToPay);
372	                if (pool.isEmpty()) {
373	                    return;
374	                }
375	            }
376	        }
377	
378	        // snow
379	        for (ManaCost cost : this) {
380	            if (!cost.isPaid() && cost instanceof SnowManaCost) {
381	                cost.assignPayment(game, ability, pool, costToPay);
382	                if (pool.isEmpty()) {
383	                    return;
384	                }
385	            }
386	        }
387	
388	        // generic
389	        for (ManaCost cost : this) {
390	            if (!cost.isPaid() && cost instanceof GenericManaCost) {
391	                cost.assignPayment(game, ability, pool, costToPay);
392	                if (pool.isEmpty()) {
393	                    return;
394	                }
395	            }
396	        }
397	
398	        // variable (generic)
399	        for (ManaCost cost : this) {
400	            if (!cost.isPaid() && cost instanceof VariableManaCost) {
401	                cost.assignPayment(game, ability, pool, costToPay);
402	            }
403	        }
404	
405	        // stop using mana of the clicked mana type
406	        pool.lockManaType();
407	        if (canUseManaType == null) {
408	            handleForcedToPayOnlyForCurrentPayment(game, pool, referenceCosts);
409	        }
410	    }
411	
412	    private void handleForcedToPayOnlyForCurrentPayment(Game game, ManaPool pool, ManaCosts referenceCosts) {
413	        // for Word of Command
414	        if (pool.isForcedToPay()) {
415	            if (referenceCosts != null && this.getText().equals(referenceCosts.getText())) {
416	                UUID playerId = pool.getPlayerId();
417	                Player player = game.getPlayer(playerId);
418	                if (player != null) {
419	                    game.undo(playerId);
420	                    this.clearPaid();
421	
422	                    // TODO: checks Word of Command with {X}{X} cards
423	                    int amount = 0;
424	                    List<VariableCost> variableCosts = getVariableCosts();
425	                    if (!variableCosts.isEmpty()) {
426	                        amount = variableCosts.get(0).getAmount();
427	                    }
428	                    this.setX(amount, amount);
429	
430	                    player.getManaPool().restoreMana(pool.getPoolBookmark());
431	                    game.bookmarkState();
