        if (testMana.getAny() > 0) {
            return true;
        }
        switch (mana) {
            case B:
                return testMana.getBlack() > 0;
            case U:
                return testMana.getBlue() > 0;
            case R:
                return testMana.getRed() > 0;
            case W:
                return testMana.getWhite() > 0;
            case G:
                return testMana.getGreen() > 0;
        }
