104	    /**
105	     * @param manaType      the mana type that should be paid
106	     * @param ability
107	     * @param filter
108	     * @param game
109	     * @param costToPay     complete costs to pay (needed to check conditional
110	     *                      mana)
111	     * @param usedManaToPay the information about what mana was paid
112	     * @return
113	     */
114	    public boolean pay(ManaType manaType, Ability ability, Filter filter, Game game, Cost costToPay, Mana usedManaToPay) {
115	        if (!isAutoPayment() && manaType != unlockedManaType) {
116	            // if manual payment and the needed mana type was not unlocked, nothing will be paid
117	            return false;
118	        }
119	        ManaType possibleAsThoughPoolManaType = null;
120	        if (isAutoPayment()
121	                && isAutoPaymentRestricted()
122	                && !wasManaAddedBeyondStock() // was not more mana added than at the start of casting something
123	                && manaType != unlockedManaType) {
124	            // if automatic restricted payment and there is already mana in the pool
125	            // and the needed mana type was not unlocked, nothing will be paid
126	            if (unlockedManaType != null) {
127	                ManaPoolItem checkItem = new ManaPoolItem();
128	                checkItem.add(unlockedManaType, 1);
129	                possibleAsThoughPoolManaType = game.getContinuousEffects().asThoughMana(manaType, checkItem, ability.getSourceId(), ability, ability.getControllerId(), game);
130	            }
131	            // Check if it's possible to use mana as thought for the unlocked manatype in the mana pool for this ability
132	            if (possibleAsThoughPoolManaType == null
133	                    || possibleAsThoughPoolManaType != unlockedManaType) {
134	                return false; // if it's not possible return
135	            }
136	        }
137	        // first try to pay from conditional mana (the returned manaType can be changed if AsThoughEffects are active)
138	        ConditionalManaInfo manaInfo = getConditional(manaType, ability, filter, game, costToPay, possibleAsThoughPoolManaType);
139	        if (manaInfo != null) {
140	            removeConditional(manaInfo, ability, game, costToPay, usedManaToPay);
141	            lockManaType(); // pay only one mana if mana payment is set to manually
142	            return true;
143	        }
144	
145	        for (ManaPoolItem mana : manaItems) {
146	            if (filter != null && !filter.match(mana.getSourceObject(), game)) {
147	                // If here, then mana source does not match the filter
148	                // However, alternate mana payment abilities such as convoke won't match the filter but are valid
149	                // So we need to do some ugly checks to allow them
150	                // For convoke, mana apparently comes from a spell without a mana effect, that doesn't match the ability source
151	                if (ability.getSourceId().equals(mana.getSourceId())
152	                        || !(mana.getSourceObject() instanceof Spell)
153	                        || ((Spell) mana.getSourceObject())
154	                        .getAbilities(game)
155	                        .stream()
156	                        .flatMap(a -> a.getAllEffects().stream())
157	                        .anyMatch(ManaEffect.class::isInstance)) {
158	                    continue; // if any of the above cases, not an alt mana payment ability, thus excluded by filter
159	                }
160	            }
161	            if (possibleAsThoughPoolManaType == null
162	                    && manaType != unlockedManaType
163	                    && isAutoPayment()
164	                    && isAutoPaymentRestricted()
165	                    && mana.count() == mana.getStock()) {
166	                // no mana added beyond the stock so don't auto pay this
167	                continue;
168	            }
169	            ManaType usableManaType = game.getContinuousEffects().asThoughMana(manaType, mana, ability.getSourceId(), ability, ability.getControllerId(), game);
170	            if (usableManaType == null) {
171	                continue;
172	            }
173	            if (mana.get(usableManaType) > 0) {
174	                GameEvent event = new ManaPaidEvent(ability, mana.getSourceId(), mana.getFlag(), mana.getOriginalId(), mana.getSourceObject(), usableManaType);
175	                game.fireEvent(event);
176	                usedManaToPay.increase(usableManaType);
177	                mana.remove(usableManaType);
178	                if (mana.count() == 0) { // so no items with count 0 stay in list
179	                    manaItems.remove(mana);
180	                }
181	                lockManaType(); // pay only one mana if mana payment is set to manually
182	                return true;
183	            }
184	        }
185	        return false;
186	    }
