225	        int count = 0;
226	        for (ConditionalMana mana : getConditionalMana()) {
227	            if (mana.apply(ability, game, mana.getManaProducerId(), costToPay)) {
228	                count += mana.count(filter);
229	            }
230	        }
231	        return count;
232	    }
