269	                    continue;
270	                }
271	                if (doNotEmptyManaTypes.contains(manaType)) {
272	                    continue;
273	                }
274	                if (manaBecomesBlack) {
275	                    continue;
276	                }
277	                if (manaBecomesRed) {
278	                    continue;
279	                }
280	                if (manaBecomesColorless) {
