290	    public int emptyPool(Game game) {
291	        int total = 0;
292	        Iterator<ManaPoolItem> it = manaItems.iterator();
293	        while (it.hasNext()) {
294	            ManaPoolItem item = it.next();
295	            ConditionalMana conditionalItem = item.getConditionalMana();
296	            for (ManaType manaType : ManaType.values()) {
297	                if (doNotEmptyManaTypes.contains(manaType)) {
298	                    continue;
299	                }
300	                if (item.get(manaType) > 0) {
301	                    total += emptyItem(item, item, game, manaType);
302	                }
303	                if (conditionalItem != null
304	                        && conditionalItem.get(manaType) > 0) {
305	                    total += emptyItem(item, conditionalItem, game, manaType);
306	                }
307	            }
308	            if (item.count() == 0) {
309	                it.remove();
310	            }
311	        }
312	        return total;
313	    }
