315	    private int emptyItem(ManaPoolItem item, Emptiable toEmpty, Game game, ManaType manaType) {
316	        switch (item.getDuration()) {
317	            case EndOfTurn:
318	                if (game.getTurnPhaseType() != TurnPhase.END) {
319	                    return 0;
320	                }
321	                break;
322	            case EndOfCombat:
323	                if (game.getTurnPhaseType() != TurnPhase.COMBAT
324	                        || game.getTurnStepType() != PhaseStep.END_COMBAT) {
325	                    return 0;
326	                }
327	        }
328	
329	        // TODO: This should be reimplemented as replacement effects instead, so you can choose which applies.
330	        if (manaBecomesBlack) {
331	            int amount = toEmpty.get(manaType);
332	            toEmpty.clear(manaType);
333	            toEmpty.add(ManaType.BLACK, amount);
334	            return 0;
335	        }
336	        if (manaBecomesRed) {
337	            int amount = toEmpty.get(manaType);
338	            toEmpty.clear(manaType);
339	            toEmpty.add(ManaType.RED, amount);
340	            return 0;
341	        }
342	        if (manaBecomesColorless) {
343	            int amount = toEmpty.get(manaType);
344	            toEmpty.clear(manaType);
345	            toEmpty.add(ManaType.COLORLESS, amount);
346	            return 0;
347	        }
348	        int amount = toEmpty.get(manaType);
349	        toEmpty.clear(manaType);
350	        return amount;
351	    }
